func (q *Queries) UpdateDraftInvoice(ctx context.Context, arg UpdateDraftInvoiceParams) error {
	_, err := q.db.Exec(ctx, updateDraftInvoice,
		arg.ID,
		arg.TenantID,
		arg.BranchID,
		arg.GeneratedRunID,
		arg.SubtotalMinor,
		arg.FundedDeductionMinor,
		arg.TotalDueMinor,
		arg.CalculationDetails,
	)
	return err
}
